from pyats import aetest
from genie.utils import Dq

class CommonSetup(aetest.CommonSetup):
    @aetest.subsection
    def connect(self, testbed):
        testbed.devices['lab-sw1'].connect()

class ValidateVlans(aetest.Testcase):
    @aetest.test
    def vlan_100_present(self, testbed):
        out = testbed.devices['lab-sw1'].parse('show vlan brief')
        vlans = Dq(out).contains('vlan_id').get_values('vlan_id')
        assert 100 in vlans, f"VLAN 100 missing, saw {vlans}"

class CommonCleanup(aetest.CommonCleanup):
    @aetest.subsection
    def disconnect(self, testbed):
        testbed.devices['lab-sw1'].disconnect()
EOF
